import{_ as a,c as e,o as m,b as t}from"./app.b5c11ed0.js";const d='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 31-33","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 31-33","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-01-23T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/31-33/index.md"}',p={},u=t('<div class="stanza"><a href="#s3.31" id="s3.31" class="num">3.31</a><div class="sans"><p>\u0928 \u0915\u0947\u0935\u0932\u0902 \u0938\u0943\u0937\u094D\u091F\u093F\u0926\u0936\u093E\u092F\u093E\u0902 \u0928\u093F\u091C\u0936\u0915\u094D\u0924\u093F\u0935\u093F\u0915\u093E\u0938\u094B\u093D\u0938\u094D\u092F \u0935\u093F\u0936\u094D\u0935\u0902 \u092F\u0924\u094D\u0924\u0924\u094D\u092A\u0943\u0937\u094D\u0920\u092A\u093E\u0924\u093F\u0928\u094C\u2014</p><blockquote><p><strong>\u0938\u094D\u0925\u093F\u0924\u093F\u0932\u092F\u094C\u0965\u0969\u0967\u0965</strong></p></blockquote><p>\u0938\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u092A\u094D\u0930\u091A\u092F \u0907\u0924\u094D\u092F\u0928\u0941\u0935\u0930\u094D\u0924\u0924\u0947\u0964 \u0915\u094D\u0930\u093F\u092F\u093E\u0936\u0915\u094D\u0924\u094D\u092F\u093E\u092D\u093E\u0938\u093F\u0924\u0938\u094D\u092F \u0935\u093F\u0936\u094D\u0935\u0938\u094D\u092F \u0924\u0924\u094D\u0924\u0924\u094D\u092A\u094D\u0930\u092E\u093E\u0924\u094D\u0930\u092A\u0947\u0915\u094D\u0937\u0902 \u0915\u091E\u094D\u091A\u093F\u0924\u094D\u0915\u093E\u0932\u0902 \u092C\u0939\u093F\u0930\u094D\u092E\u0941\u0916\u0924\u094D\u0935\u093E\u0935\u092D\u093E\u0938\u0928\u0930\u0942\u092A\u093E \u092F\u093E \u0938\u094D\u0925\u093F\u0924\u093F\u0936\u094D\u091A\u093F\u0928\u094D\u092E\u092F\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0935\u093F\u0936\u094D\u0930\u093E\u0928\u094D\u0924\u094D\u092F\u093E\u0924\u094D\u092E\u093E \u091A \u092F\u094B \u0932\u092F\u0938\u094D\u0924\u093E\u0935\u0947\u0924\u093E\u0935\u0947\u0924\u0938\u094D\u092F \u0938\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u092A\u094D\u0930\u091A\u092F \u090F\u0935 \u0924\u0924\u094D\u0924\u0926\u094D\u0935\u0947\u0926\u094D\u092F\u0902 \u0939\u094D\u092F\u093E\u092D\u093E\u0938\u092E\u093E\u0928\u0902 \u0935\u093F\u0932\u0940\u092F\u092E\u093E\u0928\u0902 \u091A \u0928\u093F\u091C\u0938\u0902\u0935\u093F\u091A\u094D\u091B\u0915\u094D\u0924\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u092E\u0947\u0935\u093E\u0928\u094D\u092F\u0925\u093E\u0938\u094D\u092F \u0938\u0902\u0935\u0947\u0926\u0928\u093E\u0928\u0941\u092A\u092A\u0924\u094D\u0924\u0947\u0903\u0964 \u0905\u0924 \u090F\u0935 \u0936\u094D\u0930\u0940\u0915\u093E\u0932\u093F\u0915\u093E\u0915\u094D\u0930\u092E\u0947</p><blockquote><p>\u0905\u0938\u094D\u0924\u093F\u0928\u093E\u0938\u094D\u0924\u093F\u0935\u093F\u092D\u093E\u0917\u0947\u0928...\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u0926\u093F \u0938\u094D\u0925\u093F\u0924\u093F\u0932\u092F\u092A\u0930\u0924\u094D\u0935\u0947\u0928\u094B\u0915\u094D\u0924\u092E\u094D\u0964 \u0924\u0925\u093E</p><blockquote><p>\u0938\u0930\u094D\u0935\u0902 \u0936\u0941\u0926\u094D\u0927\u0902 \u0928\u093F\u0930\u093E\u0932\u092E\u094D\u092C\u0902 \u091C\u094D\u091E\u093E\u0928\u0902 \u0938\u094D\u0935\u092A\u094D\u0930\u0924\u094D\u092F\u092F\u093E\u0924\u094D\u092E\u0915\u092E\u094D\u0964<br> \u092F\u0903 \u092A\u0936\u094D\u092F\u0924\u093F \u0938 \u092E\u0941\u0915\u094D\u0924\u093E\u0924\u094D\u092E\u093E \u091C\u0940\u0935\u0928\u094D\u0928\u0947\u0935 \u0928 \u0938\u0902\u0936\u092F\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u0969\u0967\u0965</p></div><hr><div class="trans"><p>Na kevala\u1E41 s\u1E5B\u1E63\u1E6Dida\u015B\u0101y\u0101\u1E41 nija\u015Baktivik\u0101so&#39;sya vi\u015Bva\u1E41 yattatp\u1E5B\u1E63\u1E6Dhap\u0101tinau\u2014</p><blockquote><p><strong>Sthitilayau||31||</strong></p></blockquote><p>Sva\u015Baktipracaya ityanuvartate| Kriy\u0101\u015Bakty\u0101bh\u0101sitasya vi\u015Bvasya tattatpram\u0101trapek\u1E63a\u1E41 ka\xF1citk\u0101la\u1E41 bahirmukhatv\u0101vabh\u0101sanar\u016Bp\u0101 y\u0101 sthiti\u015Bcinmayapram\u0101t\u1E5Bvi\u015Br\u0101nty\u0101tm\u0101 ca yo layast\u0101vet\u0101vetasya sva\u015Baktipracaya eva tattadvedya\u1E41 hy\u0101bh\u0101sam\u0101na\u1E41 vil\u012Byam\u0101na\u1E41 ca nijasa\u1E41vicchakty\u0101tmakamev\u0101nyath\u0101sya sa\u1E41vedan\u0101nupapatte\u1E25| Ata eva \u015Br\u012Bk\u0101lik\u0101krame</p><blockquote><p>Astin\u0101stivibh\u0101gena...|</p></blockquote><p>ity\u0101di sthitilayaparatvenoktam| Tath\u0101</p><blockquote><p>Sarva\u1E41 \u015Buddha\u1E41 nir\u0101lamba\u1E41 j\xF1\u0101na\u1E41 svapratyay\u0101tmakam|<br> Ya\u1E25 pa\u015Byati sa mukt\u0101tm\u0101 j\u012Bvanneva na sa\u1E41\u015Baya\u1E25||</p></blockquote><p>iti||31||</p></div><hr><p>\u041D\u0435 <em>(na)</em> \u0442\u043E\u043B\u044C\u043A\u043E <em>(kevalam)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] <em>(vi\u015Bva)</em> \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435\u043C [\u0438\u043B\u0438 \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u043D\u0438\u0435\u043C] <em>(vik\u0101sa\u1E25)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(nija... asya)</em> \u0441\u0438\u043B\u044B <em>(\u015Bakti)</em> \u043D\u0430 \u044D\u0442\u0430\u043F\u0435, \u0438\u043B\u0438 (\u0432) \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(da\u015B\u0101y\u0101m)</em> [\u0435\u0435] \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(s\u1E5B\u1E63\u1E6Di)</em>, [\u043D\u043E \u044D\u0442\u043E \u0442\u0430\u043A\u0436\u0435] \u0432\u0435\u0440\u043D\u043E \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 <em>(yad)</em> \u0434\u0432\u0443\u0445 \u0434\u0440\u0443\u0433\u0438\u0445 [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439], \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0445 <em>(p\u1E5B\u1E63\u1E6Dhap\u0101tinau)</em> \u0437\u0430 \u044D\u0442\u0438\u043C <em>(tad)</em>\u2014</p><blockquote><p><strong>\u041F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439] <em>(sthiti)</em> [\u0438 \u0435\u0435] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(layau)</em> [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0442\u0430\u043A\u0436\u0435 \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u043D\u0438\u0435\u043C \u0435\u0433\u043E \u0421\u0438\u043B\u044B]||31||</strong></p></blockquote><p>[\u0424\u0440\u0430\u0437\u0430] &quot;[\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0442\u0430\u043A\u0436\u0435] \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u043D\u0438\u0435\u043C <em>(pracaya\u1E25)</em> \u0435\u0433\u043E <em>(sva)</em> \u0421\u0438\u043B\u044B <em>(\u015Bakti... iti)</em>&quot; [\u0434\u043E\u043B\u0436\u043D\u0430] \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u044C \u0437\u0430 <em>(anuvartate)</em> [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C \u0434\u043B\u044F \u043F\u043E\u043B\u043D\u043E\u0442\u044B \u0441\u043C\u044B\u0441\u043B\u0430] --\u0432\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u043E\u043D\u0430 \u0431\u044B\u043B\u0430 \u0434\u043E\u0431\u0430\u0432\u043B\u0435\u043D\u0430 \u0432 \u043A\u0440\u0443\u0433\u043B\u044B\u0435 \u0441\u043A\u043E\u0431\u043A\u0438 \u043A \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0443 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430--|</p><p>Sthiti, \u0438\u043B\u0438 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 <em>(sthiti\u1E25)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bvasya)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0435 <em>(\u0101bh\u0101sitasya)</em> \u0421\u0438\u043B\u043E\u0439 <em>(\u015Bakty\u0101)</em> \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(kriy\u0101)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 --\u0442.\u0435. sthiti-- <em>(y\u0101)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(r\u016Bp\u0101)</em> \u0432\u043D\u0435\u0448\u043D\u0438\u043C <em>(bahirmukhatva)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C <em>(avabh\u0101sana)</em> [\u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439] \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0435 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E <em>(ka\xF1cid)</em> \u0432\u0440\u0435\u043C\u0435\u043D\u0438 <em>(k\u0101lam)</em>, \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 <em>(apek\u1E63am)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 <em>(tad-tad)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0445 <em>(pram\u0101t\u1E5B)</em><sup>1</sup></p><p>, \u0438 <em>(ca)</em> laya, \u0438\u043B\u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(laya\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(ya\u1E25)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(\u0101tm\u0101)</em> \u043F\u043E\u043A\u043E\u0435\u043C <em>(vi\u015Br\u0101nti)</em> \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E --\u0432\u0430\u0448\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438-- <em>(pram\u0101t\u1E5B)</em>, \u043A\u0442\u043E \u0435\u0441\u0442\u044C \u0447\u0438\u0441\u0442\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(cit-maya)</em>, \u044D\u0442\u0438 \u0441\u0430\u043C\u044B\u0435 \u0434\u0432\u0430 --sthiti \u0438 laya-- <em>(tau etau)</em><sup>2</sup> [\u2014 \u044D\u0442\u043E] \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u043D\u0438\u0435 <em>(pracaya\u1E25)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(etasya sva)</em> \u0421\u0438\u043B\u044B <em>(\u015Bakti)</em> --\u0421\u0438\u043B\u044B Yog\u012B, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0440\u0430\u0432\u0435\u043D \u015Aiva--. \u0411\u0435\u0441\u0441\u043F\u043E\u0440\u043D\u043E <em>(hi)</em>, \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 <em>(tad-tad)</em> \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u044B\u0435 --\u043E\u0431\u044A\u0435\u043A\u0442\u044B-- <em>(vedyam)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(\u0101bh\u0101sam\u0101nam)</em> \u0438 <em>(ca)</em> \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0442 <em>(vil\u012Byam\u0101nam)</em> --\u0442.\u0435. \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u043C\u0438 \u0438 \u043D\u0435\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u043C\u0438-- \u0441\u043E\u0441\u0442\u043E\u044F\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0438\u0437 <em>(\u0101tmakam eva)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(nija)</em> \u0421\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u0421\u0438\u043B\u044B --\u0442.\u0435. \u0421\u0438\u043B\u044B \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(sa\u1E41vid-\u015Bakti)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0431\u044B\u043B\u043E \u0431\u044B \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E <em>(anyath\u0101... anupapatte\u1E25)</em> \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 <em>(sa\u1E41vedana)</em> \u044D\u0442\u043E\u0439 [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439] <em>(asya)</em> --\u0431\u0443\u0434\u0443\u0447\u0438 \u043C\u0435\u043D\u0435\u0435 \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u044B\u043C, \u043D\u043E \u0431\u043E\u043B\u0435\u0435 \u0442\u043E\u0447\u043D\u044B\u043C&quot;\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u044D\u0442\u043E\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u0438\u043D\u0430\u0447\u0435 \u0431\u044B\u043B\u043E \u0431\u044B \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u043C&quot;, \u0442.\u0435. \u0435\u0441\u043B\u0438 \u0431\u044B \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0438\u0435\u0441\u044F \u0438 \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0449\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u044B \u043D\u0435 \u0431\u044B\u043B\u0438 \u0431\u044B \u0442\u043E\u043B\u044C\u043A\u043E \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0438\u043B\u043E\u0439, \u0430\u043A\u0442 \u0438\u0445 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F \u0431\u044B\u043B \u0431\u044B \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u0435\u043D--|</p><p>\u041F\u043E \u0442\u043E\u0439 \u0436\u0435 \u0441\u0430\u043C\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas eva)</em>, [\u043A\u043E\u0433\u0434\u0430] \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C K\u0101lik\u0101krama <em>(\u015Br\u012B-k\u0101lik\u0101krame)</em> [\u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E, \u0447\u0442\u043E]:</p><blockquote><p>&quot;\u0418\u043C\u0435\u0435\u0442\u0441\u044F \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 --\u0442.\u0435. \u0441/\u0447\u0435\u0440\u0435\u0437 \u0434\u0435\u043B\u0435\u043D\u0438\u0435-- <em>(vibh\u0101gena)</em> \u043D\u0430 \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u044B\u0435 \u0438 \u043D\u0435\u0433\u0430\u0442\u0438\u0432\u043D\u044B\u0435 bh\u0101va-s, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u044B --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0435 \u0438 \u043D\u0435\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0435--, \u0438 \u0442.\u0434. <em>(asti-na-asti... ity\u0101di)</em>&quot;||</p></blockquote><p>[\u0442\u0430\u043A\u043E\u0435 \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u0438\u0435] \u0431\u044B\u043B\u043E \u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 <em>(paratvena)</em> \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439] <em>(sthiti-laya)</em>|</p><p>\u041F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(tath\u0101)</em>:</p><blockquote><p>&quot;\u041E\u043D <em>(sa\u1E25)</em>, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 <em>(pa\u015Byati)</em> \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E <em>(sarvam)</em> \u0447\u0438\u0441\u0442\u043E\u0435 <em>(\u015Buddham)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043B\u0438\u0448\u0435\u043D\u043E \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0438 --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043D\u0435 \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043E\u0442 \u043A\u0430\u043A\u043E\u0433\u043E-\u043B\u0438\u0431\u043E \u043E\u0431\u044A\u0435\u043A\u0442\u0430 \u0434\u043B\u044F \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F-- <em>(nis-\u0101lambam)</em> [\u0438] \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tmakam)</em> \u2014 \u044D\u0442\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(sva)</em> \u042F - \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 pratyaya <em>(pratyaya)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0439 \u0434\u0443\u0448\u043E\u0439 <em>(mukta-\u0101tm\u0101)</em> \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438 <em>(j\u012Bvan eva)</em><sup>3</sup>; [\u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u044D\u0442\u043E\u0433\u043E] \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439 <em>(na sa\u1E41\u015Baya\u1E25... iti)</em>&quot;||</p></blockquote><p>||31||</p><hr><ol><li><p>\u0414\u043B\u044F \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u0431\u043E\u043B\u044C\u0448\u0435\u0433\u043E \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0430 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u043E \u0441\u0435\u043C\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0445, \u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u043F\u0440\u0438\u043C\u0435\u0447\u0430\u043D\u0438\u0435 4 \u0432 III, 19 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F.</p></li><li><p>\u0414\u043B\u044F \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432: &quot;tau&quot; \u2014 \u044D\u0442\u043E \u0434\u0432\u043E\u0439\u043D\u043E\u0439 \u043D\u043E\u043C\u0438\u043D\u0430\u0442\u0438\u0432 (\u043C\u0443\u0436.\u0440.) \u043E\u0442 &quot;tad&quot; \u0438 &quot;etau&quot; \u2014 \u0434\u0432\u043E\u0439\u043D\u043E\u0439 \u043D\u043E\u043C\u0438\u043D\u0430\u0442\u0438\u0432 (\u043C\u0443\u0436.\u0440.) \u043E\u0442 &quot;etad&quot;. \u041E\u0431\u044B\u0447\u043D\u043E &quot;tad&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0442\u043E\u0442&quot;, \u0430 &quot;\u044D\u0442\u043E\u0442&quot; \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442\u0441\u044F \u0441\u043B\u043E\u0432\u043E\u043C &quot;etad&quot;. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, &quot;tad&quot; \u043C\u043E\u0436\u0435\u0442 \u0442\u0430\u043A\u0436\u0435 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0442\u044C &quot;\u044D\u0442\u043E\u0442&quot; \u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0430. \u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u043F\u0435\u0440\u0435\u0432\u043E\u0434 &quot;tau&quot; \u043A\u0430\u043A &quot;\u044D\u0442\u0438 \u0434\u0432\u0430&quot; \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0431\u043E\u043B\u0435\u0435 \u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0438\u043C, \u0447\u0435\u043C \u0435\u0433\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043A\u0430\u043A &quot;\u0442\u0435 \u0434\u0432\u0430&quot;. \u0418 \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 &quot;\u0441\u0430\u043C\u044B\u0439&quot;, \u043A\u043E\u0433\u0434\u0430 &quot;tad&quot; \u0438 &quot;etad&quot; \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044E\u0442\u0441\u044F \u0432\u043C\u0435\u0441\u0442\u0435, \u0442.\u0435. tau etau (\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E 6^\u043E\u043C\u0443 \u041F\u0435\u0440\u0432\u0438\u0447\u043D\u043E\u043C\u0443 \u041F\u0440\u0430\u0432\u0438\u043B\u0443 \u0413\u043B\u0430\u0441\u043D\u044B\u0445 \u0421\u0430\u043D\u0434\u0445\u0438, \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0432 &quot;t\u0101vetau&quot;... \u043D\u043E \u0430\u0432\u0442\u043E\u0440 \u043C\u043E\u0433 \u043F\u043E \u0441\u0432\u043E\u0435\u043C\u0443 \u0432\u044B\u0431\u043E\u0440\u0443 \u043D\u0430\u043F\u0438\u0441\u0430\u0442\u044C &quot;t\u0101 etau&quot; \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E 7<sup>\u043E\u043C\u0443</sup> \u041F\u0435\u0440\u0432\u0438\u0447\u043D\u043E\u043C\u0443 \u041F\u0440\u0430\u0432\u0438\u043B\u0443 \u0413\u043B\u0430\u0441\u043D\u044B\u0445 \u0421\u0430\u043D\u0434\u0445\u0438): &quot;\u0442\u0435 \u0441\u0430\u043C\u044B\u0435 \u0434\u0432\u0430&quot; \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u043A\u0430\u043A \u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, &quot;\u044D\u0442\u0438 \u0441\u0430\u043C\u044B\u0435 \u0434\u0432\u0430&quot;. \u0412\u044B \u0442\u0430\u043A\u0436\u0435 \u043C\u043E\u0436\u0435\u0442\u0435 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0442\u044C, \u0447\u0442\u043E \u044F \u0441\u043A\u0430\u0437\u0430\u043B \u043E &quot;tad&quot; \u0442\u0430\u043A\u0436\u0435 \u0432 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0438 &quot;\u044D\u0442\u043E&quot; \u043F\u0440\u043E\u0441\u0442\u043E \u043E\u0431\u0440\u0430\u0442\u0438\u0432\u0448\u0438\u0441\u044C \u043A \u043B\u044E\u0431\u043E\u043C\u0443 \u043F\u0440\u0438\u043B\u0438\u0447\u043D\u043E\u043C\u0443 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u043C\u0443 \u0441\u043B\u043E\u0432\u0430\u0440\u044E.</p></li><li><p>\u0414\u043B\u044F \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432 \u043E\u043F\u044F\u0442\u044C: \u041A\u043E\u0433\u0434\u0430 &quot;n&quot; \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u043A\u043E\u043D\u0446\u0435 \u0441\u043B\u043E\u0432\u0430 \u0438 \u0435\u043C\u0443 \u043F\u0440\u0435\u0434\u0448\u0435\u0441\u0442\u0432\u0443\u0435\u0442 &quot;\u043A\u043E\u0440\u043E\u0442\u043A\u0430\u044F&quot; \u0433\u043B\u0430\u0441\u043D\u0430\u044F, \u043E\u043D \u043C\u0435\u043D\u044F\u0435\u0442\u0441\u044F \u043D\u0430 &quot;nn&quot;, \u0435\u0441\u043B\u0438 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u044C \u0433\u043B\u0430\u0441\u043D\u043E\u0439 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E 2<sup>\u043E\u043C\u0443</sup> \u043F\u043E\u0434-\u043F\u0440\u0430\u0432\u0438\u043B\u0443 \u0432 15<sup>\u043E\u043C</sup> \u041F\u0440\u0430\u0432\u0438\u043B\u0435 \u0421\u043E\u0433\u043B\u0430\u0441\u043D\u044B\u0445 \u0421\u0430\u043D\u0434\u0445\u0438. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0438\u0441\u0445\u043E\u0434\u043D\u043E\u0435 \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 &quot;j\u012Bvan eva&quot; \u043F\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u043B\u043E\u0441\u044C \u0432 &quot;j\u012Bvanneva&quot; \u0432 \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u0435. \u041E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u0430\u0432\u0442\u043E\u0440 \u0437\u043D\u0430\u043B \u044D\u0442\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u043E! (\u0448\u0443\u0447\u0443).</p></li></ol></div><div class="stanza"><a href="#s3.32" id="s3.32" class="num">3.32</a><div class="sans"><p>\u0928\u0928\u094D\u0935\u0947\u0935\u0902 \u0938\u0943\u0937\u094D\u091F\u093F\u0938\u094D\u0925\u093F\u0924\u093F\u0932\u092F\u093E\u0935\u0938\u094D\u0925\u093E\u0938\u094D\u0935\u0928\u094D\u092F\u094B\u0928\u094D\u092F\u092D\u0947\u0926\u093E\u0935\u092D\u093E\u0938\u092E\u092F\u0940\u0937\u094D\u0935\u0938\u094D\u092F \u0938\u094D\u0935\u0930\u0942\u092A\u093E\u0928\u094D\u092F\u0925\u093E\u0924\u094D\u0935\u092E\u093E\u092F\u093E\u0924\u092E\u093F\u0924\u094D\u092F\u093E\u0936\u0919\u094D\u0915\u093E\u0936\u093E\u0928\u094D\u0924\u094D\u092F\u0930\u094D\u0925\u092E\u093E\u0939\u2014</p><blockquote><p><strong>\u0924\u0924\u094D\u092A\u094D\u0930\u0935\u0943\u0924\u094D\u0924\u093E\u0935\u092A\u094D\u092F\u0928\u093F\u0930\u093E\u0938\u0903 \u0938\u0902\u0935\u0947\u0924\u094D\u0924\u0943\u092D\u093E\u0935\u093E\u0924\u094D\u0965\u0969\u0968\u0965</strong></p></blockquote><p>\u0924\u0947\u0937\u093E\u0902 \u0938\u0943\u0937\u094D\u091F\u094D\u092F\u093E\u0926\u0940\u0928\u093E\u0902 \u092A\u094D\u0930\u0935\u0943\u0924\u094D\u0924\u093E\u0935\u092A\u094D\u092F\u0941\u0928\u094D\u092E\u091C\u094D\u091C\u0928\u0947\u093D\u092A\u093F \u0928\u093E\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u0903 \u0938\u0902\u0935\u0947\u0924\u094D\u0924\u0943\u092D\u093E\u0935\u093E\u0924\u094D\u0924\u0941\u0930\u094D\u092F\u091A\u092E\u0924\u094D\u0915\u093E\u0930\u093E\u0924\u094D\u092E\u0915\u0935\u093F\u092E\u0930\u094D\u0936\u092E\u092F\u093E\u0926\u0941\u092A\u0932\u092C\u094D\u0927\u0943\u0924\u094D\u0935\u093E\u0928\u094D\u0928\u093F\u0930\u093E\u0938\u0936\u094D\u091A\u0932\u0928\u0902 \u0924\u0928\u094D\u0928\u093F\u0930\u093E\u0938\u0947 \u0915\u0938\u094D\u092F\u091A\u093F\u0926\u092A\u094D\u092F\u092A\u094D\u0930\u0915\u093E\u0936\u0928\u093E\u0924\u094D\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0924\u0924\u094D\u0930\u0948\u0935</p><blockquote><p>\u0928\u093E\u0936\u0947\u093D\u0935\u093F\u0926\u094D\u092F\u093E\u092A\u094D\u0930\u092A\u091E\u094D\u091A\u0938\u094D\u092F \u0938\u094D\u0935\u092D\u093E\u0935\u094B \u0928 \u0935\u093F\u0928\u0936\u094D\u092F\u0924\u093F\u0964<br> \u0909\u0924\u094D\u092A\u0924\u094D\u0924\u093F\u0927\u094D\u0935\u0902\u0938\u0935\u093F\u0930\u0939\u093E\u0924\u094D\u0924\u0938\u094D\u092E\u093E\u0928\u094D\u0928\u093E\u0936\u094B \u0928 \u0935\u093E\u0938\u094D\u0924\u0935\u0903\u0965<br> \u092F\u0924\u094B\u093D\u0935\u093F\u0926\u094D\u092F\u093E \u0938\u092E\u0941\u0924\u094D\u092A\u0924\u094D\u0924\u093F\u0927\u094D\u0935\u0902\u0938\u093E\u092D\u094D\u092F\u093E\u092E\u0941\u092A\u091A\u0930\u094D\u092F\u0924\u0947\u0964<br> \u092F\u0924\u094D\u0938\u094D\u0935\u092D\u093E\u0935\u0947\u0928 \u0928\u0937\u094D\u091F\u0902 \u0928 \u0924\u0928\u094D\u0928\u0937\u094D\u091F\u0902 \u0915\u0925\u092E\u0941\u091A\u094D\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u090F\u0924\u0926\u0947\u0935 \u0938\u094D\u092A\u0928\u094D\u0926\u0947</p><blockquote><p>\u0905\u0935\u0938\u094D\u0925\u093E\u092F\u0941\u0917\u0932\u0902 \u091A\u093E\u0924\u094D\u0930 \u0915\u093E\u0930\u094D\u092F\u0915\u0930\u094D\u0924\u0943\u0924\u094D\u0935\u0936\u092C\u094D\u0926\u093F\u0924\u092E\u094D\u0964<br> \u0915\u093E\u0930\u094D\u092F\u0924\u093E \u0915\u094D\u0937\u092F\u093F\u0923\u0940 \u0924\u0924\u094D\u0930 \u0915\u0930\u094D\u0924\u0943\u0924\u094D\u0935\u0902 \u092A\u0941\u0928\u0930\u0915\u094D\u0937\u092F\u092E\u094D\u0965</p></blockquote><p>\u0924\u0925\u093E\u0964</p><blockquote><p>\u0915\u093E\u0930\u094D\u092F\u094B\u0928\u094D\u092E\u0941\u0916\u0903 \u092A\u094D\u0930\u092F\u0924\u094D\u0928\u094B \u092F\u0903 \u0915\u0947\u0935\u0932\u0902 \u0938\u094B\u093D\u0924\u094D\u0930 \u0932\u0941\u092A\u094D\u092F\u0924\u0947\u0964<br> \u0924\u0938\u094D\u092E\u093F\u0901\u0932\u094D\u0932\u0941\u092A\u094D\u0924\u0947 \u0935\u093F\u0932\u0941\u092A\u094D\u0924\u094B\u093D\u0938\u094D\u092E\u0940\u0924\u094D\u092F\u092C\u0941\u0927\u0903 \u092A\u094D\u0930\u0924\u093F\u092A\u0926\u094D\u092F\u0924\u0947\u0965<br> \u0928 \u0924\u0941 \u092F\u094B\u093D\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u094B \u092D\u093E\u0935\u0903 \u0938\u0930\u094D\u0935\u091C\u094D\u091E\u0924\u094D\u0935\u0917\u0941\u0923\u093E\u0938\u094D\u092A\u0926\u092E\u094D\u0964<br> \u0924\u0938\u094D\u092F \u0932\u094B\u092A\u0903 \u0915\u0926\u093E\u091A\u093F\u0924\u094D\u0938\u094D\u092F\u093E\u0926\u0928\u094D\u092F\u0938\u094D\u092F\u093E\u0928\u0941\u092A\u0932\u092E\u094D\u092D\u0928\u093E\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928\u094B\u0915\u094D\u0924\u092E\u094D\u0965\u0969\u0968\u0965</p></div><hr><div class="trans"><p>Nanveva\u1E41 s\u1E5B\u1E63\u1E6Disthitilay\u0101vasth\u0101svanyonyabhed\u0101vabh\u0101samay\u012B\u1E63vasya svar\u016Bp\u0101nyath\u0101tvam\u0101y\u0101tamity\u0101\u015Ba\u1E45k\u0101\u015B\u0101ntyartham\u0101ha\u2014</p><blockquote><p><strong>Tatprav\u1E5Btt\u0101vapyanir\u0101sa\u1E25 sa\u1E41vett\u1E5Bbh\u0101v\u0101t||32||</strong></p></blockquote><p>Te\u1E63\u0101\u1E41 s\u1E5B\u1E63\u1E6Dy\u0101d\u012Bn\u0101\u1E41 prav\u1E5Btt\u0101vapyunmajjane&#39;pi n\u0101sya yogina\u1E25 sa\u1E41vett\u1E5Bbh\u0101v\u0101tturyacamatk\u0101r\u0101tmakavimar\u015Bamay\u0101dupalabdh\u1E5Btv\u0101nnir\u0101sa\u015Bcalana\u1E41 tannir\u0101se kasyacidapyaprak\u0101\u015Ban\u0101t| Yadukta\u1E41 tatraiva</p><blockquote><p>N\u0101\u015Be&#39;vidy\u0101prapa\xF1casya svabh\u0101vo na vina\u015Byati|<br> Utpattidhva\u1E41savirah\u0101ttasm\u0101nn\u0101\u015Bo na v\u0101stava\u1E25||<br> Yato&#39;vidy\u0101 samutpattidhva\u1E41s\u0101bhy\u0101mupacaryate|<br> Yatsvabh\u0101vena na\u1E63\u1E6Da\u1E41 na tanna\u1E63\u1E6Da\u1E41 kathamucyate||</p></blockquote><p>iti| Etadeva spande</p><blockquote><p>Avasth\u0101yugala\u1E41 c\u0101tra k\u0101ryakart\u1E5Btva\u015Babditam|<br> K\u0101ryat\u0101 k\u1E63ayi\u1E47\u012B tatra kart\u1E5Btva\u1E41 punarak\u1E63ayam||</p></blockquote><p>tath\u0101|</p><blockquote><p>K\u0101ryonmukha\u1E25 prayatno ya\u1E25 kevala\u1E41 so&#39;tra lupyate|<br> Tasmim\u0310\u0310llupte vilupto&#39;sm\u012Btyabudha\u1E25 pratipadyate||<br> Na tu yo&#39;ntarmukho bh\u0101va\u1E25 sarvaj\xF1atvagu\u1E47\u0101spadam|<br> Tasya lopa\u1E25 kad\u0101citsy\u0101danyasy\u0101nupalambhan\u0101t||</p></blockquote><p>ityanenoktam||32||</p></div><hr><p>\u0412\u043E\u0437\u0440\u0430\u0436\u0435\u043D\u0438\u0435 <em>(nanu)</em>!: &quot;\u0422\u0430\u043A <em>(evam)</em>, [\u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B, \u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E \u043D\u0430 \u043E\u0431\u044A\u0435\u043A\u0442\u044B,] \u0435\u0433\u043E [\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] <em>(asya)</em> \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u0435\u0442 anyath\u0101tva --\u0442.\u0435. \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435-- \u0438\u043B\u0438 \u043F\u0435\u0440\u0435\u0440\u044B\u0432 \u0432 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0438 <em>(anyath\u0101tvam \u0101y\u0101tam)</em> \u0441\u0432\u043E\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpa)</em> \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 <em>(avasth\u0101su)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439] <em>(s\u1E5B\u1E63\u1E6Di-sthiti-laya)</em>, \u0447\u044C\u0438 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(avabh\u0101sa-may\u012B\u1E63u)</em> \u043E\u0442\u043B\u0438\u0447\u0430\u044E\u0442\u0441\u044F <em>(bheda)</em> \u0434\u0440\u0443\u0433 \u043E\u0442 \u0434\u0440\u0443\u0433\u0430 <em>(anyonya... iti)</em>&quot; --\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u043E\u0442\u043B\u0438\u0447\u043D\u044B \u0434\u0440\u0443\u0433 \u043E\u0442 \u0434\u0440\u0443\u0433\u0430 \u043A\u0430\u0441\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0438\u0445 \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F, \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B \u0434\u043E\u043B\u0436\u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u043C\u0435\u043D\u044F\u0442\u044C\u0441\u044F \u043A\u0430\u0436\u0434\u044B\u0439 \u0440\u0430\u0437, \u043A\u043E\u0433\u0434\u0430 \u043E\u043D \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0442 \u044D\u0442\u0438 \u0442\u0440\u0438, \u043E\u0434\u0438\u043D \u0437\u0430 \u0434\u0440\u0443\u0433\u0438\u043C--. \u0427\u0442\u043E\u0431\u044B <em>(artham)</em> \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0438\u0442\u044C <em>(\u015B\u0101nti)</em> [\u044D\u0442\u043E] \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0435 <em>(\u0101\u015Ba\u1E45k\u0101)</em>, [\u015Aiva] \u0441\u043A\u0430\u0437\u0430\u043B <em>(\u0101ha)</em>\u2014</p><blockquote><p><strong>\u0414\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 <em>(api)</em> \u043C\u043E\u0433\u0443\u0442 \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u0443\u0442\u044C <em>(prav\u1E5Bttau)</em> \u0442\u0435 [\u0442\u0440\u0438 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439] <em>(tad)</em>, [\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B] \u043D\u0435 \u043F\u0440\u0435\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(anir\u0101sa\u1E25)</em> \u0438\u0437-\u0437\u0430 [\u0435\u0433\u043E] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u0101v\u0101t)</em> \u043A\u0430\u043A [\u0412\u044B\u0441\u0448\u0435\u0433\u043E] \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E <em>(sa\u1E41vett\u1E5B)</em>||32||</strong></p></blockquote><p>\u0414\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 <em>(api... api)</em> \u043C\u043E\u0433\u0443\u0442 \u043F\u043E\u044F\u0432\u0438\u0442\u044C\u0441\u044F <em>(prav\u1E5Bttau)</em>, [\u0438\u043B\u0438] \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u0443\u0442\u044C <em>(unmajjane)</em> \u0442\u0435 <em>(te\u1E63\u0101m)</em>, \u0442.\u0435. \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0438 \u043F\u0440. <em>(s\u1E5B\u1E63\u1E6Di-\u0101d\u012Bn\u0101m)</em>, \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u043E\u0433\u043E <em>(na)</em> \u043F\u0435\u0440\u0435\u0440\u044B\u0432\u0430 <em>(nir\u0101sa\u1E25)</em> [\u0438\u043B\u0438] \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F <em>(calanam)</em> [\u0432\u043E \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438] \u044D\u0442\u043E\u0433\u043E Yog\u012B <em>(asya yogina\u1E25)</em>, \u0438\u0437-\u0437\u0430 [\u0435\u0433\u043E] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u0101v\u0101t)</em> \u043A\u0430\u043A [\u0412\u044B\u0441\u0448\u0435\u0433\u043E] \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E <em>(svapratyaya)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C,] \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u043C, \u043F\u043E\u043B\u043D\u044B\u043C <em>(may\u0101t upalabdh\u1E5Btv\u0101t)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u043D\u043E\u0433\u043E <em>(camatk\u0101ra-\u0101tmaka)</em> \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(vimar\u015Ba)</em> Turya --\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F-- <em>(turya)</em>, [\u0438] \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u043D\u0435 \u0431\u044B\u043B\u043E \u0431\u044B \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(aprak\u0101\u015Ban\u0101t)</em> \u0447\u0435\u0433\u043E \u0431\u044B \u0442\u043E \u043D\u0438 \u0431\u044B\u043B\u043E \u0441\u043E\u0432\u0441\u0435\u043C <em>(kasyacidapi)</em> \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u043F\u0440\u0435\u0440\u044B\u0432\u0430\u043D\u0438\u044F <em>(nir\u0101se)</em> \u0432 \u0442\u043E\u043C --\u0432 \u0435\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u043A\u0430\u043A \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E-- <em>(tad)</em><sup>1</sup>|</p><p>\u0422\u0430 \u0436\u0435 [\u0438\u0441\u0442\u0438\u043D\u0430] <em>(yad)</em> \u0431\u044B\u043B\u0430 \u043F\u0440\u043E\u0434\u0435\u043A\u043B\u0430\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u0430 <em>(uktam)</em> \u0432 \u044D\u0442\u043E\u0439 \u0436\u0435 \u0441\u0430\u043C\u043E\u0439 [\u043A\u043D\u0438\u0433\u0435] --\u0432 K\u0101lik\u0101krama-- <em>(tatra eva)</em>:</p><blockquote><p>&quot;\u041A\u043E\u0433\u0434\u0430 \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(n\u0101\u015Be)</em> \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043E <em>(prapa\xF1casya)</em> \u041D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C, \u0438\u043B\u0438 M\u0101y\u0101 <em>(avidy\u0101)</em>, \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 --\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(sva-bh\u0101va\u1E25)</em> \u043D\u0435 <em>(na)</em> \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(vina\u015Byati)</em>. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 <em>(virah\u0101t)</em> \u0432\u043D\u0435\u0448\u043D\u0435\u0439 \u0432\u0438\u0434\u0438\u043C\u043E\u0441\u0442\u0438 --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F-- <em>(utpatti)</em> [\u0438] \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(dhva\u1E41sa)</em> [\u0447\u0442\u043E \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F], \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tasm\u0101t)</em> [\u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435] \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0435 <em>(v\u0101stava\u1E25)</em> \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(n\u0101\u015Ba\u1E25)</em> \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na)</em>. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yatas)</em> [\u0434\u0430\u0436\u0435] \u041D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435 <em>(avidy\u0101)</em> \u043E\u0431\u0440\u0430\u0437\u043D\u043E \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u043E <em>(upacaryate)</em> \u043A\u0430\u043A \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0435\u0441\u044F \u0438 \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0449\u0435\u0435 <em>(samutpatti-dhva\u1E41s\u0101bhy\u0101m)</em>, \u043A\u0430\u043A \u0442\u043E\u0433\u0434\u0430 <em>(katham)</em> [\u043C\u043E\u0436\u0435\u0442] \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C\u0441\u044F \u043E\u0431 <em>(ucyate)</em> \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0438 <em>(na\u1E63\u1E6Dam)</em> \u042D\u0442\u043E\u0433\u043E --\u0442.\u0435. \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(tad)</em>, [\u043A\u043E\u0433\u0434\u0430] \u044D\u0442\u043E [\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435] <em>(yad)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043F\u0440\u0438\u0440\u043E\u0434\u0435 <em>(sva-bh\u0101vena)</em>, [\u043D\u0438\u043A\u043E\u0433\u0434\u0430] \u043D\u0435 <em>(na)</em> \u0438\u0441\u0447\u0435\u0437\u0430\u043B\u043E <em>(na\u1E63\u1E6Dam... iti)</em>?&quot;||</p></blockquote><p>\u042D\u0442\u043E <em>(etad)</em> \u0431\u044B\u043B\u043E \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E <em>(uktam)</em> \u0432 \u044D\u0442\u043E\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435] <em>(anena)</em> \u0432 Spandak\u0101rik\u0101-s <em>(spande)</em>:</p><blockquote><p>&quot;\u0413\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(\u015Babditam)</em>, \u0447\u0442\u043E [\u0438\u043C\u0435\u044E\u0442\u0441\u044F] \u0434\u0432\u0430 <em>(yugalam)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(avasth\u0101)</em> \u0432 \u044D\u0442\u043E\u043C [\u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0435 Spanda] <em>(ca atra)</em>, [\u0442.\u0435.] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0434\u0435\u043B\u0430\u043D\u0438\u044F <em>(k\u0101rya... tva)</em> [\u0438] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0434\u0435\u043B\u0430\u0442\u0435\u043B\u044F <em>(kart\u1E5Btva)</em>. \u0418\u0437 \u043D\u0438\u0445 <em>(tatra)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0434\u0435\u043B\u0430\u043D\u0438\u044F <em>(k\u0101ryat\u0101)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0435\u0445\u043E\u0434\u044F\u0449\u0438\u043C <em>(k\u1E63ayi\u1E47\u012B)</em>, \u0430 <em>(punar)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0434\u0435\u043B\u0430\u0442\u0435\u043B\u044F <em>(kart\u1E5Btvam)</em> [\u2014] \u0432\u0435\u0447\u043D\u044B\u043C/\u043D\u0435\u0440\u0443\u0448\u0438\u043C\u044B\u043C <em>(ak\u1E63ayam... iti)</em>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s I, 14]</p></blockquote><p>\u0438 \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em> [\u0432 \u044D\u0442\u0438\u0445 \u0434\u0432\u0443\u0445 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430\u0445]:</p><blockquote><p>&quot;\u0422\u043E\u043B\u044C\u043A\u043E <em>(kevalam)</em> \u0443\u0441\u0438\u043B\u0438\u0435 <em>(prayatna\u1E25... sa\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(ya\u1E25)</em> \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043E <em>(unmukha\u1E25)</em> \u043D\u0430 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 <em>(k\u0101rya)</em>, \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(lupyate)</em> \u0432 \u044D\u0442\u043E\u043C [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 Sam\u0101dhi] <em>(atra)</em>. \u041A\u043E\u0433\u0434\u0430 \u044D\u0442\u043E [\u0443\u0441\u0438\u043B\u0438\u0435] \u0438\u0441\u0447\u0435\u0437\u043B\u043E <em>(tasmin lupte)</em>, [\u0442\u043E\u043B\u044C\u043A\u043E] \u0433\u043B\u0443\u043F\u0435\u0446 <em>(abudha\u1E25)</em> [\u043C\u043E\u0436\u0435\u0442] \u0434\u0443\u043C\u0430\u0442\u044C <em>(pratipadyate)</em> &#39;\u042F \u0438\u0441\u0447\u0435\u0437&#39; <em>(vilupta\u1E25 asmi iti)</em>.<br> \u041D\u0438\u043A\u043E\u0433\u0434\u0430 <em>(na tu... kad\u0101cid)</em> \u043D\u0435 \u0431\u044B\u0432\u0430\u0435\u0442 <em>(sy\u0101t)</em> \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F <em>(lopa\u1E25)</em> \u0442\u043E\u0433\u043E <em>(tasya)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E <em>(antarmukha\u1E25)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u0438\u043B\u0438 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(bh\u0101va\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(ya\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043E\u0431\u0438\u0442\u0435\u043B\u044C\u044E <em>(\u0101spadam)</em> \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 <em>(gu\u1E47a)</em> \u0432\u0441\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F <em>(sarvaj\xF1atva)</em>, \u0432\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435 \u043D\u0435\u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F <em>(anupalambhan\u0101t)</em> \u0434\u0440\u0443\u0433\u043E\u0433\u043E <em>(anyasya... iti)</em><sup>2</sup>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s I, 15-16]</p></blockquote><p>||32||</p><hr><ol><li><p>\u0418\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043F\u0440\u0438 \u043D\u0430\u043B\u0438\u0447\u0438\u0438 \u0447\u0435\u0433\u043E-\u043B\u0438\u0431\u043E \u043D\u0435\u0438\u0437\u043C\u0435\u043D\u043D\u043E\u0433\u043E. \u0415\u0441\u043B\u0438 \u0431\u044B \u0412\u044B\u0441\u0448\u0438\u0439 \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439, \u0438\u043B\u0438 \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439, \u0442.\u0435. \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 (\u0422\u044B!), \u043A\u043E\u0433\u0434\u0430-\u043B\u0438\u0431\u043E \u0438\u0437\u043C\u0435\u043D\u0438\u043B\u0441\u044F, \u0442\u043E \u0435\u0441\u0442\u044C \u0435\u0441\u043B\u0438 \u0431\u044B \u041E\u043D \u0438\u0441\u043F\u044B\u0442\u0430\u043B \u043F\u0440\u0435\u0440\u044B\u0432\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 \u0432 \u0421\u0432\u043E\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435, \u043A\u0442\u043E \u0431\u044B \u0442\u043E\u0433\u0434\u0430 \u0437\u0430\u043C\u0435\u0442\u0438\u043B \u0434\u0440\u0443\u0433\u0438\u0435 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F? \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442\u0441\u044F \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F, \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0438 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0442 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043D\u044B, \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435, \u0431\u043E\u043B\u044C, \u043F\u0443\u0441\u0442\u043E\u0442\u0430, \u0441\u0447\u0430\u0441\u0442\u044C\u0435, \u0432\u043D\u0435\u0448\u043D\u0438\u0435 \u0441\u0442\u0430\u0440\u0435\u044E\u0449\u0438\u0435 \u0432\u0435\u0449\u0438 \u0438 \u0442.\u0434.), \u0412\u044B\u0441\u0448\u0430\u044F \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C (\u0422\u044B!) \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u043F\u043E\u043A\u0438\u0434\u0430\u0435\u0442 \u0421\u0432\u043E\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435. \u042D\u0442\u043E \u2014 sadodita, \u0438\u043B\u0438 nityodita (\u0431\u0443\u043A\u0432. \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0435), \u0442.\u0435. \u0432\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u0435\u0435. \u0427\u0442\u043E \u043D\u0435\u043B\u044C\u0437\u044F \u0441\u043A\u0430\u0437\u0430\u0442\u044C \u043E\u0431\u043E \u0432\u0441\u0435\u043C, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0441\u043E\u0437\u0434\u0430\u043D\u043E \u041D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C, \u0438\u043B\u0438 M\u0101y\u0101, \u043F\u043E\u043B\u043D\u044B\u043C \u043C\u0435\u043D\u044F\u044E\u0449\u0438\u0445\u0441\u044F \u0440\u0435\u0430\u043B\u0438\u0439. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0442\u0435, \u043A\u0442\u043E \u043F\u043E\u0441\u0442\u0443\u043B\u0438\u0440\u0443\u0435\u0442, \u0447\u0442\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0438\u0437\u043C\u0435\u043D\u044F\u0435\u0442\u0441\u044F, \u0438\u043B\u0438 \u043C\u0443\u0442\u0438\u0440\u0443\u0435\u0442, \u043E\u0448\u0438\u0431\u0430\u044E\u0442\u0441\u044F \u043E\u0442 \u043D\u0430\u0447\u0430\u043B\u0430 \u0438 \u0434\u043E \u043A\u043E\u043D\u0446\u0430.</p></li><li><p>\u041D\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u043D\u043E \u043A\u0430\u0436\u0434\u044B\u0439 \u0440\u0430\u0437, \u043A\u043E\u0433\u0434\u0430 \u0432\u044B \u0432\u0438\u0434\u0438\u0442\u0435 \u0446\u0438\u0442\u0430\u0442\u0443 \u0438\u0437 Spandak\u0101rik\u0101-s, \u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0435 \u043C\u0443\u0434\u0440\u0435\u0446\u043E\u043C K\u1E63emar\u0101ja \u0432 Spandanir\u1E47aya (\u0435\u0433\u043E \u043D\u0430\u0443\u0447\u043D\u043E\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 Spandak\u0101rik\u0101-s).</p></li></ol></div><div class="stanza"><a href="#s3.33" id="s3.33" class="num">3.33</a><div class="sans"><p>\u0905\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u0903\u2014</p><blockquote><p><strong>\u0938\u0941\u0916\u0926\u0941\u0903\u0916\u092F\u094B\u0930\u094D\u092C\u0939\u093F\u0930\u094D\u092E\u0928\u0928\u092E\u094D\u0965\u0969\u0969\u0965</strong></p></blockquote><p>\u0935\u0947\u0926\u094D\u092F\u0938\u094D\u092A\u0930\u094D\u0936\u091C\u093E\u0924\u092F\u094B\u0903 \u0938\u0941\u0916\u0926\u0941\u0903\u0916\u092F\u094B\u0930\u094D\u092C\u0939\u093F\u0930\u093F\u0935 \u0928\u0940\u0932\u093E\u0926\u093F\u0935\u0926\u093F\u0926\u0928\u094D\u0924\u093E\u092D\u093E\u0938\u0924\u092F\u093E \u092E\u0928\u0928\u0902 \u0938\u0902\u0935\u0947\u0926\u0928\u0902 \u0928 \u0924\u0941 \u0932\u094C\u0915\u093F\u0915\u0935\u0926\u0939\u0928\u094D\u0924\u093E\u0938\u094D\u092A\u0930\u094D\u0936\u0928\u0947\u0928\u093E\u0938\u094D\u092F \u0939\u093F \u0938\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u092A\u094D\u0930\u091A\u092F\u094B\u093D\u0938\u094D\u092F \u0935\u093F\u0936\u094D\u0935\u092E\u094D (\u0969-\u0969\u0966) \u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u0938\u0942\u0924\u094D\u0930\u093E\u0930\u094D\u0925\u0928\u0940\u0924\u094D\u092F\u093E \u0938\u0930\u094D\u0935\u092E\u0939\u0928\u094D\u0924\u093E\u091A\u094D\u091B\u093E\u0926\u093F\u0924\u0924\u094D\u0935\u0947\u0928 \u0938\u094D\u092B\u0941\u0930\u0924\u093F \u0928 \u0924\u0941 \u0928\u093F\u092F\u0924\u0902 \u0938\u0941\u0916\u0926\u0941\u0903\u0916\u093E\u0926\u094D\u092F\u0947\u0935\u0947\u0924\u094D\u092F\u0947\u0935\u092E\u094D\u092A\u0930\u092E\u0947\u0924\u0924\u094D\u0964 \u092F\u094B\u0917\u0940 \u0939\u093F \u092A\u094D\u0930\u0936\u093E\u0928\u094D\u0924\u092A\u0941\u0930\u094D\u092F\u0937\u094D\u091F\u0915\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u092D\u093E\u0935\u0903 \u0915\u0925\u0902 \u0938\u0941\u0916\u0926\u0941\u0903\u0916\u093E\u092D\u094D\u092F\u093E\u0902 \u0938\u094D\u092A\u0943\u0936\u094D\u092F\u0924\u0947\u0964 \u0924\u0925\u093E \u091A \u0936\u094D\u0930\u0940\u092A\u094D\u0930\u0924\u094D\u092F\u092D\u093F\u091C\u094D\u091E\u093E\u0938\u0942\u0924\u094D\u0930\u0935\u093F\u092E\u0930\u094D\u0936\u093F\u0928\u094D\u092F\u093E\u092E\u094D\u0964</p><blockquote><p>\u0917\u094D\u0930\u093E\u0939\u0915\u092D\u0942\u092E\u093F\u0915\u094B\u0924\u094D\u0924\u0940\u0930\u094D\u0923\u093E\u0928\u093E\u0902 \u0935\u093E\u0938\u094D\u0924\u0935\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0926\u0936\u093E\u092A\u094D\u0930\u092A\u0928\u094D\u0928\u093E\u0928\u093E\u0902 \u0924\u0924\u094D\u0924\u0924\u094D\u0938\u094D\u0935\u0939\u0947\u0924\u0942\u092A\u0938\u094D\u0925\u093E\u092A\u093F\u0924\u0938\u0941\u0916\u0926\u0941\u0903\u0916\u0938\u093E\u0915\u094D\u0937\u093E\u0924\u094D\u0915\u093E\u0930\u0947\u093D\u092A\u093F \u0928 \u0924\u0947\u0937\u093E\u0902 \u0938\u0941\u0916\u0926\u0941\u0903\u0916\u093E\u0926\u093F \u0928\u094B\u0924\u094D\u092A\u0926\u094D\u092F\u0924 \u090F\u0935 \u0935\u093E \u0938\u0941\u0916\u093E\u0926\u093F \u0939\u0947\u0924\u0941\u0935\u0948\u0915\u0932\u094D\u092F\u093E\u0924\u094D\u0938\u0939\u091C\u093E\u0928\u0928\u094D\u0926\u093E\u0935\u093F\u0930\u094D\u092D\u093E\u0935\u0938\u094D\u0924\u0941 \u0924\u0926\u093E \u0938\u094D\u092F\u093E\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u092E\u094D\u0964 \u0905\u0924 \u090F\u0935</p><blockquote><p>\u0928 \u0926\u0941\u0903\u0916\u0902 \u0928 \u0938\u0941\u0916\u0902 \u092F\u0924\u094D\u0930 \u0928 \u0917\u094D\u0930\u093E\u0939\u094D\u092F\u0902 \u0917\u094D\u0930\u093E\u0939\u0915\u094B \u0928 \u091A\u0964<br> \u0928 \u091A\u093E\u0938\u094D\u0924\u093F \u092E\u0942\u0922\u092D\u093E\u0935\u094B\u093D\u092A\u093F \u0924\u0926\u0938\u094D\u0924\u093F \u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F \u0938\u094D\u092A\u0928\u094D\u0926\u0947 \u0928\u093F\u0930\u0942\u092A\u093F\u0924\u092E\u094D\u0965\u0969\u0969\u0965</p></div><hr><div class="trans"><p>Asya yogina\u1E25\u2014</p><blockquote><p><strong>Sukhadu\u1E25khayorbahirmananam||33||</strong></p></blockquote><p>Vedyaspar\u015Baj\u0101tayo\u1E25 sukhadu\u1E25khayorbahiriva n\u012Bl\u0101divadidant\u0101bh\u0101satay\u0101 manana\u1E41 sa\u1E41vedana\u1E41 na tu laukikavadahant\u0101spar\u015Banen\u0101sya hi sva\u015Baktipracayo&#39;sya vi\u015Bvam (3-30) ityuktas\u016Btr\u0101rthan\u012Bty\u0101 sarvamahant\u0101cch\u0101ditatvena sphurati na tu niyata\u1E41 sukhadu\u1E25kh\u0101dyevetyevamparametat| Yog\u012B hi pra\u015B\u0101ntapurya\u1E63\u1E6Dakapram\u0101t\u1E5Bbh\u0101va\u1E25 katha\u1E41 sukhadu\u1E25kh\u0101bhy\u0101\u1E41 sp\u1E5B\u015Byate| Tath\u0101 ca \u015Br\u012Bpratyabhij\xF1\u0101s\u016Btravimar\u015Biny\u0101m|</p><blockquote><p>Gr\u0101hakabh\u016Bmikott\u012Br\u1E47\u0101n\u0101\u1E41 v\u0101stavapram\u0101t\u1E5Bda\u015B\u0101prapann\u0101n\u0101\u1E41 tattatsvahet\u016Bpasth\u0101pitasukhadu\u1E25khas\u0101k\u1E63\u0101tk\u0101re&#39;pi na te\u1E63\u0101\u1E41 sukhadu\u1E25kh\u0101di notpadyata eva v\u0101 sukh\u0101di hetuvaikaly\u0101tsahaj\u0101nand\u0101virbh\u0101vastu tad\u0101 sy\u0101t||</p></blockquote><p>ityuktam| Ata eva</p><blockquote><p>Na du\u1E25kha\u1E41 na sukha\u1E41 yatra na gr\u0101hya\u1E41 gr\u0101hako na ca|<br> Na c\u0101sti m\u016B\u1E0Dhabh\u0101vo&#39;pi tadasti param\u0101rthata\u1E25||</p></blockquote><p>iti spande nir\u016Bpitam||33||</p></div><hr><p>\u0427\u0442\u043E \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F \u044D\u0442\u043E\u0433\u043E Yog\u012B <em>(asya yogina\u1E25)</em>\u2014</p><blockquote><p><strong>[\u042D\u0442\u043E\u0442 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u0439 Yog\u012B] \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442 <em>(mananam)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u0431\u043E\u043B\u044C <em>(sukhadu\u1E25khayo\u1E25)</em> \u043A\u0430\u043A \u043D\u0435\u0447\u0442\u043E \u0432\u043D\u0435\u0448\u043D\u0435\u0435 <em>(bahis)</em>||33||</strong></p></blockquote><p>[\u042D\u0442\u043E\u0442 \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B] \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442 --\u0431\u0443\u043A\u0432. \u0440\u0430\u0441\u0441\u043C\u043E\u0442\u0440\u0435\u043D\u0438\u0435-- <em>(mananam)</em> [\u0438\u043B\u0438] \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 --\u0431\u0443\u043A\u0432. \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435-- <em>(sa\u1E41vedanam)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u0431\u043E\u043B\u044C <em>(sukha-du\u1E25khayo\u1E25)</em>, \u0440\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0435 <em>(j\u0101tayo\u1E25)</em> \u043E\u0442 \u043A\u043E\u043D\u0442\u0430\u043A\u0442\u0430 <em>(spar\u015Ba)</em> \u0441 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438 <em>(vedya)</em>, \u043A\u0430\u043A \u043F\u0440\u043E\u0441\u0442\u043E --\u0431\u0443\u043A\u0432. \u043A\u0430\u043A \u043F\u0440\u043E\u0441\u0442\u043E\u0435 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435-- <em>(\u0101bh\u0101satay\u0101)</em> &quot;\u042D\u0442\u043E&quot; --\u0442.\u0435. \u043A\u0430\u043A \u043D\u0435\u0447\u0442\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u043E\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u042F&quot;, \u0438\u043B\u0438 &quot;\u0421\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C&quot;-- <em>(idant\u0101)</em>. [\u0412\u043A\u0440\u0430\u0442\u0446\u0435, \u043E\u043D \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442, \u0438\u043B\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u044D\u0442\u0438 \u0434\u0432\u0430] \u043A\u0430\u043A <em>(iva)</em> \u043D\u0435\u0447\u0442\u043E \u0432\u043D\u0435\u0448\u043D\u0435\u0435 <em>(bahis)</em>, [\u0442\u0430\u043A\u043E\u0435] \u043A\u0430\u043A <em>(vat)</em> \u0433\u043E\u043B\u0443\u0431\u043E\u0439 <em>(n\u012Bla)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u0430 \u043D\u0435 \u0442\u0430\u043A <em>(na tu)</em>, \u043A\u0430\u043A <em>(vat)</em> \u043E\u0431\u044B\u0447\u043D\u044B\u0435 \u043B\u044E\u0434\u0438 <em>(laukika)</em> [\u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442 \u044D\u0442\u0443 \u043F\u0430\u0440\u0443,] \u043A\u0430\u043A \u043D\u0435\u0447\u0442\u043E, \u043A\u0430\u0441\u0430\u044E\u0449\u0435\u0435\u0441\u044F --\u0432\u0441\u0442\u0443\u043F\u0430\u044E\u0449\u0435\u0435 \u0432 \u043A\u043E\u043D\u0442\u0430\u043A\u0442-- <em>(spar\u015Banena)</em> \u0441 &quot;\u042F&quot; <em>(ahant\u0101)</em>. \u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 <em>(asya hi)</em>, \u043A\u0430\u043A \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043E <em>(ukta... n\u012Bty\u0101)</em> \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435\u043C <em>(artha)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 <em>(s\u016Btra)</em> &quot;\u0412\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(vi\u015Bvam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435\u043C, \u0438\u043B\u0438 \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u043D\u0438\u0435\u043C <em>(pracaya\u1E25)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva... asya)</em> \u0421\u0438\u043B\u044B <em>(\u015Bakti)</em>. (III, 30) [\u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u043C\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(3-30 iti)</em>&quot;, \u0432\u0441\u0435 <em>(sarvam)</em> \u0441\u0438\u044F\u0435\u0442 \u043D\u0430\u0440\u0443\u0436\u0443 <em>(sphurati)</em> \u043A\u0430\u043A \u043E\u0434\u0435\u0442\u043E\u0435 --\u0432 \u0441\u043C\u044B\u0441\u043B\u0435 &quot;\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437, \u043F\u043E\u043B\u043D\u043E\u0435&quot;-- <em>(\u0101cch\u0101ditatvena)</em> \u0432 [\u0435\u0433\u043E] \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(ahant\u0101)</em>, \u0430 \u043D\u0435 <em>(na tu)</em> [\u043A\u0430\u043A \u0435\u0441\u043B\u0438] \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435, \u0431\u043E\u043B\u044C \u0438 \u0442.\u0434. <em>(sukha-du\u1E25kha-\u0101di eva)</em> \u0431\u044B\u043B\u0438 \u0431\u044B \u0441\u0432\u044F\u0437\u0430\u043D\u044B [\u0441 \u0435\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C] --\u043A\u0430\u043A \u0435\u0441\u043B\u0438 \u044D\u0442\u0438 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u044F \u043A\u0430\u043A\u0438\u043C-\u0442\u043E \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u0437\u0430\u0442\u0440\u0430\u0433\u0438\u0432\u0430\u043B\u0438 \u0431\u044B \u0435\u0433\u043E &quot;\u042F&quot;, \u0438\u043B\u0438 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443-- <em>(niyatam)</em>. \u0422\u0430\u043A\u043E\u0432\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E <em>(iti evam)</em> \u044D\u0442\u043E\u043C\u0443 <em>(etad)</em> \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0435\u043C\u0443 [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0443] <em>(param)</em>|</p><p>\u041A\u0430\u043A <em>(katham)</em> [\u043C\u043E\u0436\u0435\u0442] Yog\u012B <em>(yog\u012B hi)</em>, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(bh\u0101va\u1E25)</em>, [\u043A\u0430\u0441\u0430\u0442\u0435\u043B\u044C\u043D\u043E] \u0442\u043E\u043D\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430 --\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0438\u0437 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430, \u044D\u0433\u043E, \u0443\u043C\u0430 \u0438 \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432-- <em>(purya\u1E63\u1E6Daka)</em> \u043A\u0430\u043A \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E, \u0438\u043B\u0438 \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E --\u0421\u0430\u043C\u043E\u0441\u0442\u0438-- <em>(pram\u0101t\u1E5B)</em>, \u0431\u044B\u043B\u043E \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u043E <em>(pra\u015B\u0101nta)</em>, \u0431\u044B\u0442\u044C \u0437\u0430\u0442\u0440\u043E\u043D\u0443\u0442\u044B\u043C --\u0442.\u0435. \u0431\u044B\u0442\u044C \u043F\u043E\u0434 \u0432\u043E\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C-- <em>(sp\u1E5B\u015Byate)</em> \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435\u043C \u0438 \u0431\u043E\u043B\u044C\u044E <em>(sukha-du\u1E25kh\u0101bhy\u0101m)</em>, [\u043A\u043E\u0433\u0434\u0430 \u044D\u0442\u0438 \u0434\u0432\u0430 \u0441\u043E\u043E\u0442\u043D\u043E\u0441\u044F\u0442\u0441\u044F \u0441 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u043E\u043C, \u044D\u0433\u043E \u0438 \u0443\u043C\u043E\u043C]?|</p><p>\u0422\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(tath\u0101 ca... uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u0439 Pratyabhij\xF1\u0101s\u016Btravimar\u015Bin\u012B <em>(\u015Br\u012B-pratyabhij\xF1\u0101s\u016Btravimar\u015Biny\u0101m)</em>:</p><blockquote><p>&quot;\u041D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na)</em> \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F, \u0431\u043E\u043B\u0438 \u0438 \u0442.\u0434. <em>(sukhadu\u1E25kh\u0101di)</em> \u0434\u043B\u044F \u0442\u0435\u0445 <em>(te\u1E63\u0101m)</em>, \u043A\u0442\u043E \u043F\u0440\u0435\u0432\u0437\u043E\u0448\u0435\u043B <em>(utt\u012Br\u1E47\u0101n\u0101m)</em> \u0443\u0440\u043E\u0432\u0435\u043D\u044C <em>(bh\u016Bmik\u0101)</em> [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E] \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E --\u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u0435\u043C\u043E\u0433\u043E \u041D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C, \u0438\u043B\u0438 M\u0101y\u0101-- <em>(gr\u0101haka)</em> [\u0438] \u0434\u043E\u0441\u0442\u0438\u0433 <em>(prapann\u0101n\u0101m)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(da\u015B\u0101)</em> \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E <em>(v\u0101stava)</em> \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E --\u0442.\u0435. \u015Aiva-- <em>(pram\u0101t\u1E5B)</em>, \u0434\u0430\u0436\u0435 \u043A\u043E\u0433\u0434\u0430 <em>(api)</em> \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u044F\u0441\u043D\u043E\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 <em>(s\u0101k\u1E63\u0101tk\u0101re)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F <em>(sukha)</em> [\u0438] \u0431\u043E\u043B\u0438 <em>(du\u1E25kha)</em>, \u0432\u044B\u0437\u0432\u0430\u043D\u043D\u043E\u0435 <em>(upasth\u0101pita)</em> \u0438\u0445 <em>(sva)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 <em>(tad-tad)</em> \u043F\u0440\u0438\u0447\u0438\u043D\u0430\u043C\u0438 <em>(hetu)</em><sup>1</sup></p></blockquote><p>. \u0418\u043B\u0438 \u0435\u0449\u0435 <em>(v\u0101)</em>, [\u0438\u0437-\u0437\u0430 \u043F\u043E\u043B\u043D\u043E\u0433\u043E \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u0432 \u0421\u0432\u0435\u0442 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F,] \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435 \u0438 \u0442.\u0434. <em>(sukha-\u0101di)</em> \u043D\u0435 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u044F\u0442\u0441\u044F --\u0431\u0443\u043A\u0432. \u043D\u0435 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442\u0441\u044F-- <em>(na utpadyate eva)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0442 \u0438\u0445 \u043F\u0440\u0438\u0447\u0438\u043D\u044B <em>(hetu-vaikaly\u0101t)</em><sup>2</sup>. \u0422\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>, [\u0431\u0443\u0434\u044C \u0442\u043E \u0432 Turya, \u0438\u043B\u0438 \u0432 Tury\u0101t\u012Bta], \u0435\u0441\u0442\u044C [\u0442\u043E\u043B\u044C\u043A\u043E] <em>(sy\u0101t)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u043D\u0430\u043B\u0438\u0447\u0438\u0435 <em>(\u0101vis-bh\u0101va\u1E25)</em> \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(sahaja)</em> \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(\u0101nanda)</em> \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(tu... iti)</em>&quot;||</p><p>\u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(atas eva)</em>, \u044D\u0442\u0438\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C] <em>(anena)</em>, \u0431\u044B\u043B\u0430 \u043A\u043E\u043D\u0441\u0442\u0430\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0430 [\u0442\u0430 \u0436\u0435 \u0441\u0430\u043C\u0430\u044F \u0438\u0441\u0442\u0438\u043D\u0430] <em>(nir\u016Bpitam)</em> \u0432 Spandak\u0101rik\u0101-s <em>(spande)</em>:</p><blockquote><p>&quot;\u0413\u0434\u0435 <em>(yatra)</em> [\u043D\u0435\u0442] \u043D\u0438 <em>(na)</em> \u0431\u043E\u043B\u0438 <em>(du\u1E25kham)</em>, \u043D\u0438 <em>(na)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F <em>(sukham)</em>, \u043D\u0438 <em>(na)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u0430 <em>(gr\u0101hyam)</em>, \u043D\u0438 <em>(na ca)</em> \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430 <em>(gr\u0101hakam)</em>; [\u0433\u0434\u0435] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(bh\u0101va\u1E25)</em> \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(m\u016B\u1E0Dha)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u043D\u0435 <em>(na ca)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(asti)</em>... \u044D\u0442\u043E <em>(tad)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(asti)</em>, \u0432 \u0432\u044B\u0441\u0448\u0435\u043C \u0441\u043C\u044B\u0441\u043B\u0435 <em>(param\u0101rthatas... iti)</em>, [\u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u043C Spanda]&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s I, 5]</p></blockquote><p>||33||</p><hr><ol><li><p>\u042D\u0442\u0438 \u0432\u0435\u043B\u0438\u043A\u0438\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u043D\u0435 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u044E\u0442 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u0431\u043E\u043B\u0438 \u0434\u0430\u0436\u0435 \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0438 \u043E\u043F\u0438\u0440\u0430\u044E\u0442\u0441\u044F \u043D\u0430 Turya (\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435), \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0441\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044F. \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442 \u0434\u0440\u0430\u043C\u0443 \u043C\u0438\u0440\u043E\u0432\u043E\u0433\u043E \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430 \u043A\u0430\u043A \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0438, \u0438 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043D\u0435 \u043C\u043E\u0433\u0443\u0442 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0442\u044C \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u0431\u043E\u043B\u044C \u043A\u0430\u043A \u0447\u0442\u043E-\u0442\u043E, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0435 \u0441 \u0438\u0445 \u0438\u0441\u0442\u0438\u043D\u043D\u044B\u043C &quot;\u042F&quot;. \u041E\u043D\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442 \u044D\u0442\u0443 \u043F\u0430\u0440\u0443 \u043A\u0430\u043A \u043D\u0435\u0447\u0442\u043E \u0432\u043D\u0435\u0448\u043D\u0435\u0435.</p></li><li><p>\u041A\u043E\u0433\u0434\u0430 \u0432\u0435\u043B\u0438\u043A\u0438\u0435 Yog\u012B-s \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442 Tury\u0101t\u012Bta, \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0435\u0433\u043E\u0441\u044F \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E (\u0442.\u0435. \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0438 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442 \u0447\u0438\u0441\u0442\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u043A\u0430\u043A\u043E\u0433\u043E-\u043B\u0438\u0431\u043E \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F), \u043F\u0440\u0438\u0447\u0438\u043D\u044B \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F \u0438 \u0431\u043E\u043B\u0438 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0442. \u041F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C (r\u0101ga) \u0438 \u043E\u0442\u0432\u0440\u0430\u0449\u0435\u043D\u0438\u0435 (dve\u1E63a) \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C\u0438 \u043F\u0440\u0438\u0447\u0438\u043D\u0430\u043C\u0438 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F (sukha) \u0438 \u0431\u043E\u043B\u0438 (du\u1E25kha). \u041A\u043E\u0433\u0434\u0430 \u043F\u0440\u0438\u0447\u0438\u043D\u044B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0442, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D \u0432 \u0421\u0432\u0435\u0442 \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438, \u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u044F \u0432\u043E\u043E\u0431\u0449\u0435 \u043D\u0435 \u043C\u043E\u0433\u0443\u0442 \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u0443\u0442\u044C. \u041F\u0440\u043E\u0441\u0442\u043E!</p></li></ol></div>',3),o=[u];function s(i,n,r,k,v,y){return m(),e("div",null,o)}var q=a(p,[["render",s]]);export{d as __pageData,q as default};
